export const compareStrategiesBodyRequestsItemRiskMakerFeePctMax = 1;

export const compareStrategiesBodyRequestsItemRiskTakerFeePctMin = 0;
export const compareStrategiesBodyRequestsItemRiskTakerFeePctMax = 1;

export const compareStrategiesBodyRequestsItemRiskSlippagePctMin = 0;
export const compareStrategiesBodyRequestsItemRiskSlippagePctMax = 1;

export const compareStrategiesBodyRequestsItemWalkForwardSplitDefault = 0.7;
export const compareStrategiesBodyRequestsItemWalkForwardSplitMin = 0.3;
export const compareStrategiesBodyRequestsItemWalkForwardSplitMax = 0.9;

export const CompareStrategiesBody = zod.object({
  requests: zod.array(
    zod.object({
      strategyId: zod.string(),
      params: zod.record(zod.string(), zod.number()),
      interval: zod
        .enum(["5m", "15m", "30m", "1h", "2h", "4h", "1d"])
        .describe("Candle timeframe"),
      lookbackDays: zod
        .number()
        .min(compareStrategiesBodyRequestsItemLookbackDaysMin)
        .max(compareStrategiesBodyRequestsItemLookbackDaysMax),
      initialCapital: zod
        .number()
        .min(compareStrategiesBodyRequestsItemInitialCapitalMin)
        .default(compareStrategiesBodyRequestsItemInitialCapitalDefault),
      risk: zod.object({
        leverage: zod
          .number()
          .min(1)
          .max(compareStrategiesBodyRequestsItemRiskLeverageMax)
          .describe("Linear leverage (10-20 recommended)"),
        atrPeriod: zod
          .number()
          .min(compareStrategiesBodyRequestsItemRiskAtrPeriodMin)
          .max(compareStrategiesBodyRequestsItemRiskAtrPeriodMax)
          .describe("Period for ATR calculation (default 14)"),
        atrMultiplierSL: zod
          .number()
          .min(compareStrategiesBodyRequestsItemRiskAtrMultiplierSLMin)
          .max(compareStrategiesBodyRequestsItemRiskAtrMultiplierSLMax)
          .describe("SL distance = ATR × this multiplier"),
        riskRewardRatio: zod
          .number()
          .min(compareStrategiesBodyRequestsItemRiskRiskRewardRatioMin)
          .max(compareStrategiesBodyRequestsItemRiskRiskRewardRatioMax)
          .describe("TP distance = SL distance × this ratio"),
        makerFeePct: zod
          .number()
          .min(compareStrategiesBodyRequestsItemRiskMakerFeePctMin)
          .max(compareStrategiesBodyRequestsItemRiskMakerFeePctMax)
          .describe("Maker fee % (e.g. 0.01 = 0.01% for limit fills like TP)"),
        takerFeePct: zod
          .number()
          .min(compareStrategiesBodyRequestsItemRiskTakerFeePctMin)
          .max(compareStrategiesBodyRequestsItemRiskTakerFeePctMax)
          .describe(
            "Taker fee % (e.g. 0.035 = 0.035% for market entries and SL)",
          ),
        slippagePct: zod
          .number()
          .min(compareStrategiesBodyRequestsItemRiskSlippagePctMin)
          .max(compareStrategiesBodyRequestsItemRiskSlippagePctMax)
          .describe(
            "Slippage % applied to market orders (entries and SL exits)",
          ),
      }),
      walkForwardSplit: zod
        .number()
        .min(compareStrategiesBodyRequestsItemWalkForwardSplitMin)
        .max(compareStrategiesBodyRequestsItemWalkForwardSplitMax)
        .default(compareStrategiesBodyRequestsItemWalkForwardSplitDefault)
        .describe("Fraction used for in-sample (rest is out-of-sample)"),
    }),
  ),
  labels: zod.array(zod.string()),
});

